7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This entity implements a simple SPI-master
11	--
12	-- Documentation:
13	-- https://github.com/open-logic/open-logic/blob/main/doc/intf/olo_intf_spi_master.md
14	--
15	-- Note: The link points to the documentation of the latest release. If you
16	--       use an older version, the documentation might not match the code.
17	
18	---------------------------------------------------------------------------------------------------
19	-- Libraries
20	---------------------------------------------------------------------------------------------------
21	library ieee;
22	    use ieee.std_logic_1164.all;
23	    use ieee.numeric_std.all;
24	    use ieee.math_real.all;
25	
26	library work;
27	    use work.olo_base_pkg_math.all;
28	    use work.olo_base_pkg_logic.all;
29	    use work.olo_base_pkg_attribute.all;
30	    use work.olo_base_pkg_string.all;
31	
32	---------------------------------------------------------------------------------------------------
33	-- Entity Declaration
34	---------------------------------------------------------------------------------------------------
35	entity olo_intf_spi_master is
36	    generic (
37	        ClkFreq_g       : real;
38	        SclkFreq_g      : real                 := 1.0e6;
39	        MaxTransWidth_g : positive             := 32;
40	        CsHighTime_g    : real                 := 20.0e-9;
41	        SpiCpol_g       : natural range 0 to 1 := 1;
42	        SpiCpha_g       : natural range 0 to 1 := 1;
43	        SlaveCnt_g      : positive             := 1;
44	        LsbFirst_g      : boolean              := false;
45	        MosiIdleState_g : std_logic            := '0'
46	    );
47	    port (
48	        -- Control Signals
49	        Clk             : in    std_logic;
50	        Rst             : in    std_logic;
51	        -- Command Interface
52	        Cmd_Valid       : in    std_logic;
53	        Cmd_Ready       : out   std_logic;
54	        Cmd_Slave       : in    std_logic_vector(log2ceil(SlaveCnt_g) - 1 downto 0)      := (others => '0');
55	        Cmd_Data        : in    std_logic_vector(MaxTransWidth_g - 1 downto 0)           := (others => '0');
56	        Cmd_TransWidth  : in    std_logic_vector(log2ceil(MaxTransWidth_g+1)-1 downto 0) := toUslv(MaxTransWidth_g, log2ceil(MaxTransWidth_g+1));
57	        Cmd_CsHold      : in    std_logic                                                := '0';
58	        -- Response Interface
59	        Resp_Valid      : out   std_logic;
60	        Resp_Data       : out   std_logic_vector(MaxTransWidth_g - 1 downto 0);
61	        -- SPI
62	        Spi_Sclk        : out   std_logic;
63	        Spi_Mosi        : out   std_logic;
64	        Spi_Miso        : in    std_logic                                                := '0';
65	        Spi_Cs_n        : out   std_logic_vector(SlaveCnt_g - 1 downto 0)
66	    );
67	end entity;
68	
69	---------------------------------------------------------------------------------------------------
70	-- Architecture Declaration
71	---------------------------------------------------------------------------------------------------
72	architecture rtl of olo_intf_spi_master is
73	
74	    -- *** Types ***
75	    type State_t is (Idle_s, SftComp_s, ClkInact_s, ClkAct_s, CsHigh_s);
76	
77	    -- *** Constants ***
78	    constant EntityName_c     : string  := "olo_intf_spi_master";
79	    constant ClkDiv_c         : natural := integer(round(ClkFreq_g/SclkFreq_g));
80	    constant ClkDivThres_c    : natural := ClkDiv_c / 2 - 1;
81	    constant CsHighCycles_c   : natural := integer(ceil(ClkFreq_g*CsHighTime_g));
82	    constant SclkFreqResult_c : real    := ClkFreq_g/(2.0*real(ClkDivThres_c+1));
83	
84	    -- *** Two Process Method ***
85	    type TwoProcess_r is record
86	        State      : State_t;
87	        StateLast  : State_t;
88	        shiftReg   : std_logic_vector(MaxTransWidth_g - 1 downto 0);
89	        RdData     : std_logic_vector(MaxTransWidth_g - 1 downto 0);
90	        Spi_Cs_n   : std_logic_vector(SlaveCnt_g - 1 downto 0);
91	        Spi_Sclk   : std_logic;
92	        Spi_Mosi   : std_logic;
93	        ClkDivCnt  : integer range 0 to ClkDivThres_c;
94	        BitCnt     : integer range 0 to MaxTransWidth_g;
95	        CsHighCnt  : integer range 0 to CsHighCycles_c - 1;
96	        Busy       : std_logic;
97	        Done       : std_logic;
98	        MosiNext   : std_logic;
99	        TransWidth : integer range 0 to MaxTransWidth_g;
100	        CsHold     : std_logic;
101	    end record;
102	
103	    signal r, r_next : TwoProcess_r;
104	
105	    -- Signal required for automatic constraining
106	    signal SpiMiso_i : std_logic;
107	
108	    -- Synthesis attributes - preserve register
109	    attribute dont_merge of SpiMiso_i   : signal is DontMerge_SuppressChanges_c;
110	    attribute preserve of SpiMiso_i     : signal is Preserve_SuppressChanges_c;
111	    attribute keep of SpiMiso_i         : signal is Keep_SuppressChanges_c;
112	    attribute dont_touch of SpiMiso_i   : signal is DontTouch_SuppressChanges_c;
113	    attribute syn_keep of SpiMiso_i     : signal is SynKeep_SuppressChanges_c;
114	    attribute syn_preserve of SpiMiso_i : signal is SynPreserve_SuppressChanges_c;
115	
116	    -- *** Functions and procedures ***
117	    function getClockLevel (ClkActive : boolean) return std_logic is
118	    begin
119	        if SpiCpol_g = 0 then
120	            if ClkActive then
121	                return '1';
122	            else
123	                return '0';
124	            end if;
125	        else
126	            if ClkActive then
127	                return '0';
128	            else
129	                return '1';
130	            end if;
131	        end if;
132	    end function;
133	
134	    procedure shiftReg (
135	        signal BeforeShift  : in std_logic_vector(MaxTransWidth_g-1 downto 0);
136	        variable AfterShift : out std_logic_vector(MaxTransWidth_g-1 downto 0);
137	        signal InputBit     : in std_logic;
138	        variable OutputBit  : out std_logic;
139	        TransWidth          : in integer range 0 to MaxTransWidth_g) is
140	    begin
141	        if LsbFirst_g then
142	            OutputBit                := BeforeShift(0);
143	            AfterShift               := '0' & BeforeShift(BeforeShift'high downto 1);
144	            AfterShift(TransWidth-1) := InputBit;
145	        else
146	            OutputBit  := BeforeShift(TransWidth-1);
147	            AfterShift := BeforeShift(BeforeShift'high - 1 downto 0) & InputBit;
148	        end if;
149	    end procedure;
150	
151	begin
152	
153	    -----------------------------------------------------------------------------------------------
154	    -- Assertions
155	    -----------------------------------------------------------------------------------------------
156	    assert abs(SclkFreqResult_c/SclkFreq_g - 1.0) < 0.1
157	        report errorMessage(EntityName_c, "SclkFreq_g is not within 10% of the actual Sclk frequency")
158	        severity error;
159	
160	    -----------------------------------------------------------------------------------------------
161	    -- Combinatorial Proccess
162	    -----------------------------------------------------------------------------------------------
163	    SpiMiso_i <= Spi_Miso;
164	
165	    p_comb : process (all) is
166	        variable v : TwoProcess_r;
167	    begin
168	        -- *** hold variables stable ***
169	        v := r;
170	
171	        -- *** Default Values ***
172	        v.Done := '0';
173	
174	        -- *** State Machine ***
175	        case r.State is
176	            when Idle_s =>
177	                -- Start of Transfer
178	                if Cmd_Valid = '1' then
179	                    v.shiftReg   := Cmd_Data;
180	                    v.State      := SftComp_s;
181	                    v.Busy       := '1';
182	                    v.TransWidth := fromUslv(Cmd_TransWidth);
183	                    v.CsHold     := Cmd_CsHold;
184	                    -- Assert only the selectec CS, put others to '1' for the case of CS hold in previous transfer
185	                    -- and now selecting a different slave
186	                    v.Spi_Cs_n                                  := (others => '1');
187	                    v.Spi_Cs_n(to_integer(unsigned(Cmd_Slave))) := '0';
188	                end if;
189	                v.CsHighCnt := 0;
190	                v.ClkDivCnt := 0;
191	                v.BitCnt    := 0;
192	
193	            when SftComp_s =>
194	                v.State := ClkInact_s;
195	                -- Compensate shift for CPHA 0
196	                if SpiCpha_g = 0 then
197	                    shiftReg(r.shiftReg, v.shiftReg, SpiMiso_i, v.MosiNext, r.TransWidth);
198	                end if;
199	
200	            when ClkInact_s =>
201	                v.Spi_Sclk := getClockLevel(false);
202	                -- Apply/Latch data if required
203	                if r.ClkDivCnt = 0 then
204	                    if SpiCpha_g = 0 then
205	                        v.Spi_Mosi := r.MosiNext;
206	                    else
207	                        shiftReg(r.shiftReg, v.shiftReg, SpiMiso_i, v.MosiNext, r.TransWidth);
208	                    end if;
209	                end if;
210	                -- Clock period handling
211	                if r.ClkDivCnt = ClkDivThres_c then
212	                    -- All bits done
213	                    if r.BitCnt = r.TransWidth then
214	                        v.Spi_Mosi := MosiIdleState_g;
215	                        v.State    := CsHigh_s;
216	                    -- Otherwise contintue
217	                    else
218	                        v.State := ClkAct_s;
219	                    end if;
220	                    v.ClkDivCnt := 0;
221	                else
222	                    v.ClkDivCnt := r.ClkDivCnt + 1;
223	                end if;
224	
225	            when ClkAct_s =>
226	                v.Spi_Sclk := getClockLevel(true);
227	                -- Apply data if required
228	                if r.ClkDivCnt = 0 then
229	                    if SpiCpha_g = 1 then
230	                        v.Spi_Mosi := r.MosiNext;
231	                    else
232	                        shiftReg(r.shiftReg, v.shiftReg, SpiMiso_i, v.MosiNext, r.TransWidth);
233	                    end if;
234	                end if;
235	                -- Clock period handling
236	                if r.ClkDivCnt = ClkDivThres_c then
237	                    v.State     := ClkInact_s;
238	                    v.ClkDivCnt := 0;
239	                    v.BitCnt    := r.BitCnt + 1;
240	                else
241	                    v.ClkDivCnt := r.ClkDivCnt + 1;
242	                end if;
243	
244	            when CsHigh_s =>
245	                -- Only de-assert CS if not Cmd_CsHold, otherwise keep CS asserted for next transfer
246	                if r.CsHold = '0' then
247	                    v.Spi_Cs_n := (others => '1');
248	                end if;
249	                -- Return to idle handling
250	                if r.CsHighCnt = CsHighCycles_c - 1 then
251	                    v.State  := Idle_s;
252	                    v.Busy   := '0';
253	                    v.Done   := '1';
254	                    v.RdData := r.shiftReg;
255	                else
256	                    v.CsHighCnt := r.CsHighCnt + 1;
257	                end if;
258	
259	            -- coverage off
260	            when others => null; -- unreachable code
261	            -- coverage on
262	        end case;
263	
264	        -- *** assign signal ***
265	        r_next <= v;
266	    end process;
267	
268	    -----------------------------------------------------------------------------------------------
269	    -- Outputs
270	    -----------------------------------------------------------------------------------------------
271	    Cmd_Ready  <= not r.Busy;
272	    Resp_Valid <= r.Done;
273	    Resp_Data  <= r.RdData;
274	    Spi_Sclk   <= r.Spi_Sclk;
275	    Spi_Cs_n   <= r.Spi_Cs_n;
276	    Spi_Mosi   <= r.Spi_Mosi;
277	
278	    -----------------------------------------------------------------------------------------------
279	    -- Sequential Proccess
280	    -----------------------------------------------------------------------------------------------
281	    p_seq : process (Clk) is
282	    begin
283	        if rising_edge(Clk) then
284	            r <= r_next;
285	            if Rst = '1' then
286	                r.State    <= Idle_s;
287	                r.Spi_Cs_n <= (others => '1');
288	                r.Spi_Sclk <= getClockLevel(false);
289	                r.Busy     <= '0';
290	                r.Done     <= '0';
291	                r.Spi_Mosi <= MosiIdleState_g;
292	            end if;
293	        end if;
294	    end process;
295	
296	end architecture;
297	
