31	entity olo_intf_spi_slave is
32	    generic (
33	        TransWidth_g                : positive             := 32;
34	        SpiCpol_g                   : natural range 0 to 1 := 0;
35	        SpiCpha_g                   : natural range 0 to 1 := 0;
36	        LsbFirst_g                  : boolean              := false;
37	        ConsecutiveTransactions_g   : boolean              := false;
38	        InternalTriState_g          : boolean              := true
39	    );
40	    port (
41	        -- Control Signals
42	        Clk             : in    std_logic;
43	        Rst             : in    std_logic;
44	        -- RX Data
45	        Rx_Valid        : out   std_logic;
46	        Rx_Data         : out   std_logic_vector(TransWidth_g - 1 downto 0);
47	        -- TX Data
48	        Tx_Valid        : in    std_logic                                   := '1';
49	        Tx_Ready        : out   std_logic;
50	        Tx_Data         : in    std_logic_vector(TransWidth_g - 1 downto 0) := (others => '0');
51	        -- Response Interface
52	        Resp_Valid      : out   std_logic;
53	        Resp_Sent       : out   std_logic;
54	        Resp_Aborted    : out   std_logic;
55	        Resp_CleanEnd   : out   std_logic;
56	        -- SPI
57	        Spi_Sclk        : in    std_logic;
58	        Spi_Mosi        : in    std_logic                                   := '0';
59	        Spi_Cs_n        : in    std_logic;
60	        -- Miso with internal Tristate
61	        Spi_Miso        : out   std_logic;
62	        -- Miso with external Tristate
63	        Spi_Miso_o      : out   std_logic;
64	        Spi_Miso_t      : out   std_logic
65	    );
