178	                    v.SpiMisoData := Tx_Data(TxIdx_c);
179	                end if;
180	                -- For CPHA=0, data bust be valid on falling edge of CS immediately
181	                if SpiCpha_g = 0 and not r.IsConsecutive then
182	                    LeaveState_v := true;
