217	                        v.RxOutput := '1'; -- Done in next cycle to await shift register update
218	                        -- Transaction completed successfully
219	                        v.Resp_Valid := '1';
220	                        v.Resp_Sent  := '1';
221	                        -- If consecutive transactions are enabled, latch next Tx data
222	                        if ConsecutiveTransactions_g then
223	                            v.State       := LatchTx_s;
