243	                end if;
244	
245	            when WaitCsHigh_s => null;  -- Return to idle is handled after FSM
246	
247	            -- coverage off
248	            when others => null; -- unreachable code
249	            -- coverage on
250	        end case;
251	
252	        -- Output RX Data
253	        if r.RxOutput = '1' then
254	            v.Rx_Valid := '1';
255	            v.Rx_Data  := r.ShiftReg;
256	        end if;
257	
258	        -- Return to idle if CS is high
259	        if SpiCsn_i = '1' then
260	            v.State           := Idle_s;
261	            v.SpiMisoTristate := '1';
