31	---------------------------------------------------------------------------------------------------
32	-- vunit: run_all_in_same_sim
33	entity olo_intf_spi_master_tb is
34	    generic (
35	        BusFrequency_g              : integer              := 10_000_000;
36	        LsbFirst_g                  : boolean              := false;
37	        SpiCpha_g                   : integer range 0 to 1 := 0;
38	        SpiCpol_g                   : integer range 0 to 1 := 0;
39	        runner_cfg                  : string
40	    );
41	end entity;
42	
43	architecture sim of olo_intf_spi_master_tb is
44	
45	    -----------------------------------------------------------------------------------------------
46	    -- Fixed Generics
47	    -----------------------------------------------------------------------------------------------
48	    constant SclkFreq_c      : real      := real(BusFrequency_g);
49	    constant MaxTransWidth_c : positive  := 32;
50	    constant CsHighTime_c    : real      := 100.0e-9;
51	    constant SlaveCnt_c      : positive  := 2;
52	    constant MosiIdleState_c : std_logic := '0';
53	
54	    -----------------------------------------------------------------------------------------------
55	    -- TB Defnitions
56	    -----------------------------------------------------------------------------------------------
57	    constant Clk_Frequency_c : real := 100.0e6;
58	    constant Clk_Period_c    : time := (1 sec) / Clk_Frequency_c;
59	
60	    -----------------------------------------------------------------------------------------------
61	    -- Interface Signals
62	    -----------------------------------------------------------------------------------------------
63	    -- Contral Sginal
64	    signal Clk            : std_logic                                                := '0';
65	    signal Rst            : std_logic                                                := '0';
66	    signal Cmd_Valid      : std_logic                                                := '0';
67	    signal Cmd_Ready      : std_logic;
68	    signal Cmd_Slave      : std_logic_vector(log2ceil(SlaveCnt_c) - 1 downto 0)      := (others => '0');
69	    signal Cmd_Data       : std_logic_vector(MaxTransWidth_c - 1 downto 0)           := (others => '0');
70	    signal Cmd_TransWidth : std_logic_vector(log2ceil(MaxTransWidth_c+1)-1 downto 0) := (others => '0');
71	    signal Cmd_CsHold     : std_logic                                                := '0';
72	    signal Resp_Valid     : std_logic;
73	    signal Resp_Data      : std_logic_vector(MaxTransWidth_c - 1 downto 0);
74	    signal Spi_Sclk       : std_logic;
75	    signal Spi_Mosi       : std_logic;
76	    signal Spi_Miso       : std_logic                                                := '0';
77	    signal Spi_Cs_n       : std_logic_vector(SlaveCnt_c - 1 downto 0)                := (others => '1');
78	
79	    -----------------------------------------------------------------------------------------------
80	    -- TB Defnitions
81	    -----------------------------------------------------------------------------------------------
82	
83	    -- *** Verification Compnents ***
84	    constant Slave0_c : olo_test_spi_slave_t := new_olo_test_spi_slave(
85	        bus_frequency   => SclkFreq_c,
86	        lsb_first       => LsbFirst_g,
87	        max_trans_width => MaxTransWidth_c,
88	        cpha            => SpiCpha_g,
89	        cpol            => SpiCpol_g
90	    );
91	
92	    constant Slave1_c : olo_test_spi_slave_t := new_olo_test_spi_slave(
93	        bus_frequency   => SclkFreq_c,
94	        lsb_first       => LsbFirst_g,
95	        max_trans_width => MaxTransWidth_c,
96	        cpha            => SpiCpha_g,
97	        cpol            => SpiCpol_g
98	    );
99	
100	    procedure sendCommand (
101	        SlaveIdx              : integer;
102	        TxData                : std_logic_vector;
103	        signal Cmd_Slave      : out std_logic_vector;
104	        signal Cmd_Valid      : out std_logic;
105	        signal Cmd_Data       : out std_logic_vector;
106	        signal Cmd_TransWidth : out std_logic_vector;
107	        signal Cmd_CsHold     : out std_logic;
108	        CsHold                : in std_logic := '0') is
109	    begin
110	        wait until rising_edge(Clk);
111	        check_equal(Cmd_Ready, '1', "Cmd_Ready not asserted");
112	        Cmd_Slave                      <= toUslv(SlaveIdx, Cmd_Slave'length);
113	        Cmd_Valid                      <= '1';
114	        Cmd_Data(TxData'high downto 0) <= TxData;
115	        Cmd_TransWidth                 <= toUslv(TxData'length, Cmd_TransWidth'length);
116	        Cmd_CsHold                     <= CsHold;
117	
118	        wait until rising_edge(Clk);
119	        Cmd_Valid <= '0';
120	
121	        wait until falling_edge(Clk);
122	        check_equal(Cmd_Ready, '0', "Cmd_Ready not de-asserted");
123	
124	    end procedure;
125	
126	    procedure checkResponse (
127	        RxData : std_logic_vector) is
128	    begin
129	        wait until rising_edge(Clk) and Resp_Valid = '1';
130	        check_equal(Cmd_Ready, '1', "Cmd_Ready not asserted");
131	        check_equal(Resp_Data(RxData'high downto 0), RxData, "Unexpected RxData");
132	    end procedure;
133	
134	begin
135	
136	    -----------------------------------------------------------------------------------------------
137	    -- TB Control
138	    -----------------------------------------------------------------------------------------------
139	    test_runner_watchdog(runner, 50 ms);
140	
141	    p_control : process is
142	        variable Tx32_v, Rx32_v : std_logic_vector(31 downto 0);
143	        variable Tx16_v, Rx16_v : std_logic_vector(15 downto 0);
144	    begin
145	        test_runner_setup(runner, runner_cfg);
146	
147	        while test_suite loop
148	
149	            -- Reset
150	            wait until rising_edge(Clk);
151	            Rst <= '1';
152	            wait for 1 us;
153	            wait until rising_edge(Clk);
154	            Rst <= '0';
155	            wait until rising_edge(Clk);
156	
157	            -- *** Basics ***
158	            if run("ResetValues") then
159	                wait for 1 us;
160	                check_equal(Cmd_Ready, '1', "Cmd_Ready not asserted");
161	                check_equal(Resp_Valid, '0', "Resp_Valid");
162	                check_equal(Spi_Cs_n, onesVector(SlaveCnt_c), "Spi_Cs_n");
163	            end if;
164	
165	            -- *** Transfers ***
166	            if run("FullWidthTransfer") then
167	                -- Cmd_Slave Expectation
168	                Tx32_v := x"12345678";
169	                Rx32_v := x"DEADBEEF";
170	                spi_slave_push_transaction (net, Slave0_c, MaxTransWidth_c, data_mosi => Tx32_v, data_miso => Rx32_v);
171	
172	                -- Send command
173	                sendCommand(0, Tx32_v, Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold);
174	                checkResponse(Rx32_v);
175	            end if;
176	
177	            if run("ReducedWidthTransfer") then
178	                -- Cmd_Slave Expectation
179	                Tx16_v := x"11AA";
180	                Rx16_v := x"EE33";
181	                spi_slave_push_transaction (net, Slave0_c, 16, data_mosi => Tx16_v, data_miso => Rx16_v);
182	
183	                -- Send command
184	                sendCommand(0, Tx16_v, Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold);
185	                checkResponse(Rx16_v);
186	            end if;
187	
188	            -- *** Cmd_Slave Selection ***
189	            if run("SlaveSelection") then
190	                -- Cmd_Slave Expectation
191	                spi_slave_push_transaction (net, Slave0_c, MaxTransWidth_c, data_mosi => x"11111111", data_miso => x"22222222");
192	                spi_slave_push_transaction (net, Slave1_c, MaxTransWidth_c, data_mosi => x"33333333", data_miso => x"44444444");
193	
194	                -- Cmd_Slave 1 Transfer
195	                sendCommand(1, x"33333333", Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold);
196	                checkResponse(x"44444444");
197	
198	                -- Cmd_Slave 0 Transfer
199	                sendCommand(0, x"11111111", Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold);
200	                checkResponse(x"22222222");
201	            end if;
202	
203	            -- *** Two continuous transfers with CS going high in between (normal case) ***
204	            if run("ContinuousTransfersWithCsHigh") then
205	                -- Cmd_Slave Expectation
206	                spi_slave_push_transaction (net, Slave0_c, MaxTransWidth_c, data_mosi => x"AAAAAAAA", data_miso => x"BBBBBBBB");
207	                spi_slave_push_transaction (net, Slave0_c, MaxTransWidth_c, data_mosi => x"CCCCCCCC", data_miso => x"DDDDDDDD");
208	
209	                -- Slave Transfers
210	                sendCommand(0, x"AAAAAAAA", Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold);
211	                checkResponse(x"BBBBBBBB");
212	                sendCommand(0, x"CCCCCCCC", Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold);
213	                checkResponse(x"DDDDDDDD");
214	            end if;
215	
216	            -- *** Two continuous transfers with CS staying low in between ***
217	            if run("ContinuousTransfersWithCsLow") then
218	                -- Cmd_Slave Expectation
219	                spi_slave_push_transaction (net, Slave0_c, MaxTransWidth_c, data_mosi => x"AAAAAAAA", data_miso => x"BBBBBBBB", wait_for_csn_high => false);
220	                spi_slave_push_transaction (net, Slave0_c, MaxTransWidth_c, data_mosi => x"CCCCCCCC", data_miso => x"DDDDDDDD");
221	
222	                -- Slave Transfer 0
223	                sendCommand(0, x"AAAAAAAA", Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold, '1');
224	                checkResponse(x"BBBBBBBB");
225	                -- Check if CSn is held low
226	                check_equal(Spi_Cs_n(0), '0', "CSn not held low");
227	                -- Slave Transfer 1
228	                sendCommand(0, x"CCCCCCCC", Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold);
229	                checkResponse(x"DDDDDDDD");
230	            end if;
231	
232	            -- *** Slave Switch with CsHold ***
233	            if run("SlaveSwitchWithCsHold") then
234	                -- Cmd_Slave Expectation (Slave 0 Csn goes high due to slave s switch)
235	                spi_slave_push_transaction (net, Slave0_c, MaxTransWidth_c, data_mosi => x"AAAAAAAA", data_miso => x"BBBBBBBB");
236	                spi_slave_push_transaction (net, Slave1_c, MaxTransWidth_c, data_mosi => x"CCCCCCCC", data_miso => x"DDDDDDDD");
237	
238	                -- Slave Transfer 0
239	                sendCommand(0, x"AAAAAAAA", Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold, '1');
240	                checkResponse(x"BBBBBBBB");
241	                -- Slave Transfer 1
242	                sendCommand(1, x"CCCCCCCC", Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold);
243	                checkResponse(x"DDDDDDDD");
244	            end if;
245	
246	            -- *** Edge Cases ***
247	            if run("Cmd_ValidWhileBusy") then
248	                -- Cmd_Slave Expectation
249	                spi_slave_push_transaction (net, Slave0_c, MaxTransWidth_c, data_mosi => x"AAAAAAAA", data_miso => x"BBBBBBBB");
250	                spi_slave_push_transaction (net, Slave0_c, MaxTransWidth_c, data_mosi => x"CCCCCCCC", data_miso => x"DDDDDDDD");
251	
252	                -- Send command 1 (and start during busy)
253	                sendCommand(0, x"AAAAAAAA", Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold);
254	                check_equal(Cmd_Ready, '0', "Cmd_Ready not de-asserted");
255	                wait until rising_edge(Clk);
256	                Cmd_Valid <= '1';
257	                wait until rising_edge(Clk);
258	                Cmd_Valid <= '0';
259	                checkResponse(x"BBBBBBBB");
260	
261	                -- Send Command 2
262	                sendCommand(0, x"CCCCCCCC", Cmd_Slave, Cmd_Valid, Cmd_Data, Cmd_TransWidth, Cmd_CsHold);
263	                checkResponse(x"DDDDDDDD");
264	            end if;
265	
266	            -- *** Wait until done ***
267	            wait_until_idle(net, as_sync(Slave0_c));
268	            wait_until_idle(net, as_sync(Slave1_c));
269	            wait for 10 us;
270	
271	        end loop;
272	
273	        -- TB done
274	        test_runner_cleanup(runner);
275	    end process;
276	
277	    -----------------------------------------------------------------------------------------------
278	    -- Clock
