3	-- Authors: Oliver Bruendler
4	---------------------------------------------------------------------------------------------------
5	
6	---------------------------------------------------------------------------------------------------
7	-- Libraries
8	---------------------------------------------------------------------------------------------------
9	library ieee;
10	    use ieee.std_logic_1164.all;
11	    use ieee.numeric_std.all;
12	    use ieee.math_real.all;
13	
14	library vunit_lib;
15	    context vunit_lib.vunit_context;
16	    context vunit_lib.com_context;
17	    context vunit_lib.vc_context;
18	    use vunit_lib.queue_pkg.all;
19	    use vunit_lib.sync_pkg.all;
20	
21	library olo;
22	    use olo.olo_base_pkg_math.all;
23	    use olo.olo_base_pkg_logic.all;
24	
25	library work;
26	    use work.olo_test_spi_master_pkg.all;
27	    use work.olo_test_activity_pkg.all;
28	
29	---------------------------------------------------------------------------------------------------
30	-- Entity
31	---------------------------------------------------------------------------------------------------
32	-- vunit: run_all_in_same_sim
33	entity olo_intf_spi_slave_tb is
34	    generic (
35	        ClkFrequency_g              : integer               := 100_000_000;
36	        BusFrequency_g              : integer               := 10_000_000;
37	        TransWidth_g                : integer range 8 to 16 := 8;
38	        LsbFirst_g                  : boolean               := false;
39	        SpiCpha_g                   : integer range 0 to 1  := 0;
40	        SpiCpol_g                   : integer range 0 to 1  := 0;
41	        ConsecutiveTransactions_g   : boolean               := true;
42	        InternalTriState_g          : boolean               := true;
43	        runner_cfg                  : string
44	    );
45	end entity;
46	
47	architecture sim of olo_intf_spi_slave_tb is
48	
49	    -----------------------------------------------------------------------------------------------
50	    -- TB Defnitions
51	    -----------------------------------------------------------------------------------------------
52	    constant SclkFreq_c      : real := real(BusFrequency_g);
53	    constant Clk_Frequency_c : real := real(ClkFrequency_g);
54	    constant Clk_Period_c    : time := (1 sec) / Clk_Frequency_c;
55	
56	    -----------------------------------------------------------------------------------------------
57	    -- Interface Signals
58	    -----------------------------------------------------------------------------------------------
59	    signal Clk           : std_logic                                   := '0';
60	    signal Rst           : std_logic;
61	    signal Rx_Valid      : std_logic;
62	    signal Rx_Data       : std_logic_vector(TransWidth_g - 1 downto 0);
63	    signal Tx_Valid      : std_logic                                   := '0';
64	    signal Tx_Ready      : std_logic;
65	    signal Tx_Data       : std_logic_vector(TransWidth_g - 1 downto 0) := (others => '0');
66	    signal Resp_Valid    : std_logic;
67	    signal Resp_Sent     : std_logic;
68	    signal Resp_Aborted  : std_logic;
69	    signal Resp_CleanEnd : std_logic;
70	    signal Spi_Sclk      : std_logic                                   := choose(SpiCpol_g = 0, '0', '1');
71	    signal Spi_Mosi      : std_logic                                   := '0';
72	    signal Spi_Cs_n      : std_logic                                   := '1';
73	    signal Spi_Miso      : std_logic;
74	    signal Spi_Miso_Con  : std_logic;
75	    signal Spi_Miso_o    : std_logic;
76	    signal Spi_Miso_t    : std_logic;
77	
78	    -- shorthand for range
79	    signal D : std_logic_vector(TransWidth_g - 1 downto 0);
80	
81	    -----------------------------------------------------------------------------------------------
82	    -- TB Defnitions
83	    -----------------------------------------------------------------------------------------------
84	
85	    -- *** Verification Compnents ***
86	    constant Master_c : olo_test_spi_master_t := new_olo_test_spi_master(
87	        bus_frequency   => SclkFreq_c,
88	        lsb_first       => LsbFirst_g,
89	        max_trans_width => TransWidth_g*3,
90	        cpha            => SpiCpha_g,
91	        cpol            => SpiCpol_g
92	    );
93	
94	    -- *** Internal Messaging ***
95	    -- Rx Handling
96	    constant RxQueue_c    : queue_t    := new_queue;
97	    constant RxMsg_c      : msg_type_t := new_msg_type("Rx Message");
98	    signal RxCheckOngoing : boolean    := false;
99	
100	    procedure expectRx (
101	        Data : std_logic_vector(TransWidth_g - 1 downto 0);
102	        msg  : string := "") is
103	        variable Msg_v : msg_t := new_msg(RxMsg_c);
104	    begin
105	        push(Msg_v, Data);
106	        push_string(Msg_v, msg);
107	        push(RxQueue_c, Msg_v);
108	    end procedure;
109	
110	    procedure waitUntilRxDone is
111	    begin
112	        if (not is_empty(RxQueue_c)) or RxCheckOngoing then
113	            wait until is_empty(RxQueue_c) and (not RxCheckOngoing) and rising_edge(Clk);
114	        end if;
115	    end procedure;
116	
117	    -- Resp Handling
118	    constant RespQueue_c    : queue_t    := new_queue;
119	    constant RespMsg_c      : msg_type_t := new_msg_type("Resp Message");
120	    signal RespCheckOngoing : boolean    := false;
121	
122	    procedure expectResp (
123	        Sent     : std_logic := '0';
124	        Aborted  : std_logic := '0';
125	        CleanEnd : std_logic := '0') is
126	        variable Msg_v : msg_t := new_msg(RespMsg_c);
127	    begin
128	        push(Msg_v, Sent);
129	        push(Msg_v, Aborted);
130	        push(Msg_v, CleanEnd);
131	        push(RespQueue_c, Msg_v);
132	    end procedure;
133	
134	    procedure waitUntilRespDone is
135	    begin
136	        if (not is_empty(RespQueue_c)) or RespCheckOngoing then
137	            wait until is_empty(RespQueue_c) and (not RespCheckOngoing) and rising_edge(Clk);
138	        end if;
139	    end procedure;
140	
141	    -- Tx Handling
142	    constant TxQueue_c    : queue_t    := new_queue;
143	    constant TxMsg_c      : msg_type_t := new_msg_type("Tx Message");
144	    signal TxCheckOngoing : boolean    := false;
145	
146	    procedure applyTx (
147	        Data        : std_logic_vector(TransWidth_g - 1 downto 0);
148	        DelayCycles : integer := 0;
149	        WaitReady   : boolean := true;
150	        msg         : string  := "") is
151	        variable Msg_v : msg_t := new_msg(TxMsg_c);
152	    begin
153	        push(Msg_v, Data);
154	        push(Msg_v, DelayCycles);
155	        push(Msg_v, WaitReady);
156	        push_string(Msg_v, msg);
157	        push(TxQueue_c, Msg_v);
158	    end procedure;
159	
160	    procedure waitUntilTxDone is
161	    begin
162	        if (not is_empty(TxQueue_c)) or TxCheckOngoing then
163	            wait until is_empty(TxQueue_c) and (not TxCheckOngoing) and rising_edge(Clk);
164	        end if;
165	    end procedure;
166	
167	begin
168	
169	    -----------------------------------------------------------------------------------------------
170	    -- TB Control
171	    -----------------------------------------------------------------------------------------------
172	    test_runner_watchdog(runner, 50 ms);
173	
174	    p_control : process is
175	        variable Mosi16_v, Miso16_v : std_logic_vector(15 downto 0);
176	        variable Mosi48_v, Miso48_v : std_logic_vector(47 downto 0);
177	        variable TxVldDelay_v       : integer;
178	        constant ClkRatio_c         : real := real(ClkFrequency_g) / real(BusFrequency_g);
179	    begin
180	        test_runner_setup(runner, runner_cfg);
181	
182	        while test_suite loop
183	
184	            if ClkRatio_c < 6.0 then
185	                check(false, "ClkFrequency_g must be at least 6 times higher than BusFrequency_g");
186	            elsif ClkRatio_c < 8.0 then
187	                TxVldDelay_v := 1;
188	            elsif ClkRatio_c < 10.0 then
189	                TxVldDelay_v := 2;
190	            else
191	                TxVldDelay_v := 3;
192	            end if;
193	
194	            -- Reset
195	            wait until rising_edge(Clk);
196	            Rst <= '1';
197	            wait for 1 us;
198	            wait until rising_edge(Clk);
199	            Rst <= '0';
200	            wait until rising_edge(Clk);
201	
202	            -- *** Basics ***
203	            if run("ResetValues") then
204	                check_equal(Rx_Valid, '0', "Rx_Valid wrong after reset");
205	                check_equal(Tx_Ready, '0', "Tx_Ready wrong after reset");
206	                check_equal(Resp_Valid, '0', "Resp_Valid wrong after reset");
207	                check_equal(Spi_Miso, 'Z', "Spi_Miso wrong after reset");
208	            end if;
209	
210	            -- *** Simple Transaction ***
211	            if run("SimpleTransactions") then
212	
213	                -- Do two transactions
214	                for i in 0 to 1 loop
215	                    -- Define Data
216	                    Mosi16_v := toUslv(16#1234#+i, 16);
217	                    Miso16_v := toUslv(16#5678#+i, 16);
218	
219	                    -- Start Transaction
220	                    spi_master_push_transaction (net, Master_c, TransWidth_g, Mosi16_v(D'Range), Miso16_v(D'Range), msg => "SimpleTransaction");
221	
222	                    -- Expect RX Data
223	                    expectRx(Mosi16_v(D'Range));
224	
225	                    -- Expect Responses
226	                    expectResp(Sent => '1');
227	                    expectResp(CleanEnd => '1');
228	
229	                    -- Apply TX Data
230	                    applyTx(Miso16_v(D'Range), 0);
231	
232	                    -- Wait for Response
233	                    waitUntilRespDone;
234	                    waitUntilRxDone;
235	                    waitUntilTxDone;
236	                end loop;
237	
238	            end if;
239	
240	            if run("DelayedDataForCpha1") then
241	                if SpiCpha_g = 1 then
242	                    -- Define Data
243	                    Mosi16_v := x"ABCD";
244	                    Miso16_v := x"1357";
245	
246	                    -- Start Transaction
247	                    spi_master_push_transaction (net, Master_c, TransWidth_g, Mosi16_v(D'Range), Miso16_v(D'Range), msg => "SimpleTransaction");
248	
249	                    -- Expect RX Data
250	                    expectRx(Mosi16_v(D'Range));
251	
252	                    -- Expect Responses
253	                    expectResp(Sent => '1');
254	                    expectResp(CleanEnd => '1');
255	
256	                    -- Apply TxData
257	                    applyTx(Miso16_v(D'Range), 1);
258	
259	                end if;
260	            end if;
261	
262	            -- *** Consecutive Transactions ***
263	            if run("3ConsecutiveTransactions-CleanEnd") then
264	                -- Only execute when enabled
265	                if ConsecutiveTransactions_g then
266	                    -- Define Data
267	                    Mosi48_v := x"81F13C81468F";
268	                    Miso48_v := x"3C183C8F6481";
269	
270	                    -- Start Transaction
271	                    spi_master_push_transaction (net, Master_c, TransWidth_g*3,
272	                        Mosi48_v(TransWidth_g*3-1 downto 0), Miso48_v(TransWidth_g*3-1 downto 0),
273	                        msg => "3 Consecutive Transactions");
274	
275	                    -- Expect RX Data
276	                    if LsbFirst_g then
277	
278	                        -- Loop over three trasactions
279	                        for i in 0 to 2 loop
280	                            expectRx(Mosi48_v(TransWidth_g*(i+1)-1 downto TransWidth_g*i), "Word " & to_string(i));
281	                        end loop;
282	
283	                    else
284	
285	                        -- Loop over three trasactions
286	                        for i in 2 downto 0 loop
287	                            expectRx(Mosi48_v(TransWidth_g*(i+1)-1 downto TransWidth_g*i), "Word " & to_string(i));
288	                        end loop;
289	
290	                    end if;
291	
292	                    -- Expect Responses
293	                    for i in 0 to 2 loop
294	                        expectResp(Sent => '1');
295	                    end loop;
296	
297	                    expectResp(CleanEnd => '1');
298	
299	                    -- First word applied immediately
300	                    if LsbFirst_g then
301	                        applyTx(Miso48_v(TransWidth_g-1 downto 0), 0, msg => "Word 0");
302	                    else
303	                        applyTx(Miso48_v(TransWidth_g*3-1 downto TransWidth_g*2), 0, msg => "Word 0");
304	                    end if;
305	
306	                    -- Other TX Data applied with delay (there should be at least one clock cycle of time)
307	                    for i in 1 to 2 loop
308	                        if LsbFirst_g then
309	                            applyTx(Miso48_v(TransWidth_g*(i+1)-1 downto TransWidth_g*i), TxVldDelay_v, msg => "Word " & to_string(i));
310	                        else
311	                            applyTx(Miso48_v(TransWidth_g*(3-i)-1 downto TransWidth_g*(2-i)), TxVldDelay_v, msg => "Word " & to_string(i));
312	                        end if;
313	                    end loop;
314	
315	                end if;
316	            end if;
317	
318	            if run("2ConsecutiveTransactions-AbortEnd") then
319	                -- Only execute when enabled
320	                if ConsecutiveTransactions_g then
321	                    -- Define Data
322	                    Mosi48_v := x"1A2B3C4D5E6F";
323	                    Miso48_v := x"112233445566";
324	
325	                    -- Start Transaction
326	                    spi_master_push_transaction (net, Master_c, TransWidth_g*2,
327	                        Mosi48_v(TransWidth_g*2-1 downto 0), Miso48_v(TransWidth_g*2-1 downto 0),
328	                        msg => "2 Consecutive Transactions");
329	
330	                    -- Expect RX Data
331	                    if LsbFirst_g then
332	                        expectRx(Mosi48_v(TransWidth_g-1 downto 0), "Word 0");
333	                        expectRx(Mosi48_v(TransWidth_g*2-1 downto TransWidth_g), "Word 1");
334	                    else
335	                        expectRx(Mosi48_v(TransWidth_g*2-1 downto TransWidth_g), "Word 0");
336	                        expectRx(Mosi48_v(TransWidth_g-1 downto 0), "Word 1");
337	                    end if;
338	
339	                    -- Expect Responses
340	                    expectResp(Sent => '1');
341	                    expectResp(Sent => '1');
342	                    expectResp(Aborted => '1');
343	
344	                    -- Apply TX Data
345	                    if LsbFirst_g then
346	                        applyTx(Miso48_v(TransWidth_g-1 downto 0), 0, msg => "Word 0"); -- First one immediately
347	                        applyTx(Miso48_v(TransWidth_g*2-1 downto TransWidth_g), TxVldDelay_v, msg => "Word 1");
348	                    else
349	                        applyTx(Miso48_v(TransWidth_g*2-1 downto TransWidth_g), 0, msg => "Word 0");
350	                        applyTx(Miso48_v(TransWidth_g-1 downto 0), TxVldDelay_v, msg => "Word 1"); -- First one immediately
351	                    end if;
352	                    applyTx(Miso48_v(TransWidth_g*3-1 downto TransWidth_g*2), 1, msg => "Word 2"); -- aborted transaction;
353	                end if;
354	            end if;
355	
356	            if run("3ConsecutiveTransactions-TxNoWaitForReady") then
357	                -- Only execute when enabled
358	                if ConsecutiveTransactions_g then
359	                    -- Define Data
360	                    Mosi48_v := x"81F13C81468F";
361	                    Miso48_v := x"3C183C8F6481";
362	
363	                    -- Start Transaction
364	                    spi_master_push_transaction (net, Master_c, TransWidth_g*3,
365	                        Mosi48_v(TransWidth_g*3-1 downto 0), Miso48_v(TransWidth_g*3-1 downto 0),
366	                        msg => "3 Consecutive Transactions");
367	
368	                    -- Expect RX Data
369	                    if LsbFirst_g then
370	                        expectRx(Mosi48_v(TransWidth_g-1 downto 0), "Word 0");
371	                        expectRx(Mosi48_v(TransWidth_g*2-1 downto TransWidth_g), "Word 1");
372	                        expectRx(Mosi48_v(TransWidth_g*3-1 downto TransWidth_g*2), "Word 2");
373	                    else
374	                        expectRx(Mosi48_v(TransWidth_g*3-1 downto TransWidth_g*2), "Word 0");
375	                        expectRx(Mosi48_v(TransWidth_g*2-1 downto TransWidth_g), "Word 1");
376	                        expectRx(Mosi48_v(TransWidth_g-1 downto 0), "Word 2");
377	                    end if;
378	
379	                    -- Expect Responses
380	                    for i in 0 to 2 loop
381	                        expectResp(Sent => '1');
382	                    end loop;
383	
384	                    expectResp(CleanEnd => '1');
385	
386	                    -- Apply Data
387	                    if LsbFirst_g then
388	                        applyTx(Miso48_v(TransWidth_g-1 downto 0), 0, WaitReady => true, msg => "Word 0");
389	                        applyTx(Miso48_v(TransWidth_g*2-1 downto TransWidth_g), 0, WaitReady => false, msg => "Word 1");
390	                        applyTx(Miso48_v(TransWidth_g*3-1 downto TransWidth_g*2), 0, WaitReady => false, msg => "Word 2");
391	                    else
392	                        applyTx(Miso48_v(TransWidth_g*3-1 downto TransWidth_g*2), 0, WaitReady => true, msg => "Word 0");
393	                        applyTx(Miso48_v(TransWidth_g*2-1 downto TransWidth_g), 0, WaitReady => false, msg => "Word 1");
394	                        applyTx(Miso48_v(TransWidth_g-1 downto 0), 0, WaitReady => false, msg => "Word 2");
395	                    end if;
396	
397	                end if;
398	            end if;
399	
400	            -- *** TX Data Timeout ***
401	            if run("DataTimeout") then
402	                if SpiCpha_g = 1 then
403	                    -- Define Data
404	                    Mosi16_v := x"1357";
405	
406	                    -- Start Transaction (exect zero response due to no data)
407	                    spi_master_push_transaction (net, Master_c, TransWidth_g, Mosi16_v(D'Range), zerosVector(TransWidth_g));
408	
409	                    -- Expect RX Data
410	                    expectRx(Mosi16_v(D'Range));
411	
412	                    -- Expect Responses
413	                    expectResp(Sent => '1');
414	                    expectResp(CleanEnd => '1');
415	                end if;
416	            end if;
417	
418	            -- *** CSn operated before Sclk at start/end of transaction ***
419	            if run("CSnFirst") then
420	                -- Define Data
421	                Mosi16_v := toUslv(16#1234#, 16);
422	                Miso16_v := toUslv(16#5678#, 16);
423	
424	                -- Start Transaction
425	                spi_master_push_transaction (net, Master_c, TransWidth_g, Mosi16_v(D'Range), Miso16_v(D'Range), csn_first => true);
426	
427	                -- Expect RX Data
428	                expectRx(Mosi16_v(D'Range));
429	
430	                -- Expect Responses
431	                expectResp(Sent => '1');
432	                expectResp(CleanEnd => '1');
433	
434	                -- Apply TX Data
435	                applyTx(Miso16_v(D'Range), 0, msg => "Word 0");
436	            end if;
437	
438	            -- *** CSn going high in the middle of a transaction ***
439	            if run("CSnHighDuringTransaction") then
440	                -- Failing Transaction
441	
442	                -- Define Data
443	                Mosi16_v := toUslv(16#1234#, 16);
444	                Miso16_v := toUslv(16#5678#, 16);
445	
446	                -- Start Transaction
447	                if LsbFirst_g then
448	                    spi_master_push_transaction (net, Master_c, TransWidth_g-2,
449	                        Mosi16_v(TransWidth_g-3 downto 0), Miso16_v(TransWidth_g-3 downto 0), msg => "Failing Transaction");
450	                else
451	                    spi_master_push_transaction (net, Master_c, TransWidth_g-2,
452	                        Mosi16_v(TransWidth_g-1 downto 2), Miso16_v(TransWidth_g-1 downto 2), msg => "Failing Transaction");
453	                end if;
454	
455	                -- Expect Response (Aborted)
456	                expectResp(Aborted => '1');
457	
458	                -- Apply TX Data
459	                applyTx(Miso16_v(D'Range), 0, msg => "Word 0");
460	
461	                -- Successful Transaction
462	                -- Define Data
463	                Mosi16_v := toUslv(16#1A1B#, 16);
464	                Miso16_v := toUslv(16#3E3F#, 16);
465	
466	                -- Start Transaction
467	                spi_master_push_transaction (net, Master_c, TransWidth_g,
468	                    Mosi16_v(D'range), Miso16_v(D'range), msg => "Successful Transaction");
469	
470	                -- Expect RX Data
471	                expectRx(Mosi16_v(D'Range));
472	
473	                -- Expect Responses
474	                expectResp(Sent => '1');
475	                expectResp(CleanEnd => '1');
476	
477	                -- Apply TX Data
478	                applyTx(Miso16_v(D'Range), 0, msg => "Word 0");
479	            end if;
480	
481	            -- *** Wait until done ***
482	            waitUntilRxDone;
483	            waitUntilRespDone;
484	            waitUntilTxDone;
485	            wait_until_idle(net, as_sync(Master_c));
486	            wait for 1 us;
487	
488	        end loop;
489	
490	        -- TB done
491	        test_runner_cleanup(runner);
492	    end process;
493	
494	    -----------------------------------------------------------------------------------------------
495	    -- Clock
496	    -----------------------------------------------------------------------------------------------
497	    Clk <= not Clk after 0.5*Clk_Period_c;
498	
499	    -----------------------------------------------------------------------------------------------
500	    -- DUT
501	    -----------------------------------------------------------------------------------------------
502	    i_dut : entity olo.olo_intf_spi_slave
503	        generic map (
504	            TransWidth_g                => TransWidth_g,
505	            SpiCPol_g                   => SpiCpol_g,
506	            SpiCPha_g                   => SpiCpha_g,
507	            LsbFirst_g                  => LsbFirst_g,
508	            ConsecutiveTransactions_g   => ConsecutiveTransactions_g,
509	            InternalTriState_g          => InternalTriState_g
510	        )
511	        port map (
512	            -- Control Signals
513	            Clk             => Clk,
514	            Rst             => Rst,
515	            -- RX Data
516	            Rx_Valid        => Rx_Valid,
517	            Rx_Data         => Rx_Data,
518	            -- TX Data
519	            Tx_Valid        => Tx_Valid,
520	            Tx_Ready        => Tx_Ready,
521	            Tx_Data         => Tx_Data,
522	            -- Response Interface
523	            Resp_Valid      => Resp_Valid,
524	            Resp_Sent       => Resp_Sent,
525	            Resp_Aborted    => Resp_Aborted,
526	            Resp_CleanEnd   => Resp_CleanEnd,
527	            -- SPI
528	            Spi_Sclk        => Spi_Sclk,
529	            Spi_Mosi        => Spi_Mosi,
530	            Spi_Cs_n        => Spi_Cs_n,
531	            -- Miso with internal Tristate
532	            Spi_Miso        => Spi_Miso_Con,
533	            -- Miso with external Tristate
534	            Spi_Miso_o      => Spi_Miso_o,
535	            Spi_Miso_t      => Spi_Miso_t
536	        );
537	
538	    -- External Tri-State buffers
539	    g_tristate_ext : if not InternalTriState_g generate
540	        Spi_Miso <= 'Z' when Spi_Miso_t = '1' else Spi_Miso_o;
541	    end generate;
542	
543	    -- Internal Tri-State buffer
544	    g_tristate_int : if InternalTriState_g generate
545	        Spi_Miso <= Spi_Miso_Con;
546	    end generate;
547	
548	    -----------------------------------------------------------------------------------------------
549	    -- Verification Components
550	    -----------------------------------------------------------------------------------------------
551	    vc_master : entity work.olo_test_spi_master_vc
552	        generic map (
553	            Instance => Master_c
554	        )
555	        port map (
556	            Sclk     => Spi_Sclk,
557	            CS_n     => Spi_Cs_n,
558	            Mosi     => Spi_Mosi,
559	            Miso     => Spi_Miso
560	        );
561	
562	    -- RX Data Checker
563	    p_vc_rx : process is
564	        variable Msg_v     : msg_t;
565	        variable MsgType_v : msg_type_t;
566	        variable Data_v    : std_logic_vector(TransWidth_g - 1 downto 0);
567	        variable MsgPtr_v  : string_ptr_t;
568	    begin
569	
570	        -- loop messages
571	        loop
572	            -- wait until message available
573	            if is_empty(RxQueue_c) then
574	                wait until not is_empty(RxQueue_c) and rising_edge(Clk);
575	            end if;
576	            RxCheckOngoing <= true;
577	
578	            -- get message
579	            Msg_v     := pop(RxQueue_c);
580	            MsgType_v := message_type(Msg_v);
581	
582	            -- process message
583	            if MsgType_v = RxMsg_c then
584	                -- pop information
585	                Data_v   := pop(Msg_v);
586	                MsgPtr_v := new_string_ptr(pop_string(Msg_v));
587	
588	                -- Wait for RX data
589	                wait_for_value_stdl(Rx_Valid, '1', 1 ms, "Rx_Valid not asserted: " & to_string(MsgPtr_v));
590	                wait until rising_edge(Clk);
591	                check_equal(Rx_Data, Data_v(D'Range), "Rx_Data wrong: " & to_string(MsgPtr_v));
592	                wait until falling_edge(Clk);
593	                check_equal(Rx_Valid, '0', "Rx_Valid not deasserted: " & to_string(MsgPtr_v));
594	            else
595	                error("Unexpected message type in vc_rx");
596	            end if;
597	            RxCheckOngoing <= false;
598	        end loop;
599	
600	    end process;
601	
602	    -- Resp Checker
603	    p_vc_resp : process is
604	        variable Msg_v      : msg_t;
605	        variable MsgType_v  : msg_type_t;
606	        variable Aborted_v  : std_logic;
607	        variable Sent_v     : std_logic;
608	        variable CleanEnd_v : std_logic;
609	    begin
610	
611	        -- loop messages
612	        loop
613	            -- wait until message available
614	            if is_empty(RespQueue_c) then
615	                wait until not is_empty(RespQueue_c) and rising_edge(Clk);
616	            end if;
617	            RespCheckOngoing <= true;
618	
619	            -- get message
620	            Msg_v     := pop(RespQueue_c);
621	            MsgType_v := message_type(Msg_v);
622	
623	            -- process message
624	            if MsgType_v = RespMsg_c then
625	                -- pop information
626	                Sent_v     := pop(Msg_v);
627	                Aborted_v  := pop(Msg_v);
628	                CleanEnd_v := pop(Msg_v);
629	
630	                -- Check Resp
631	                wait_for_value_stdl(Resp_Valid, '1', 1 ms, "Resp_Valid not asserted");
632	                check_equal(Resp_Sent, Sent_v, "Resp_Sent wrong");
633	                check_equal(Resp_Aborted, Aborted_v, "Resp_Aborted wrong");
634	                check_equal(Resp_CleanEnd, CleanEnd_v, "Resp_CleanEnd not deasserted");
635	                wait until rising_edge(Clk);
636	                wait until falling_edge(Clk);
637	                check_equal(Resp_Valid, '0', "Resp_Valid not deasserted");
638	            else
639	                error("Unexpected message type in vc_resp");
640	            end if;
641	            RespCheckOngoing <= false;
642	        end loop;
643	
644	    end process;
645	
646	    -- Tx Data
647	    p_vc_tx : process is
648	        variable Msg_v         : msg_t;
649	        variable MsgType_v     : msg_type_t;
650	        variable Data_v        : std_logic_vector(TransWidth_g - 1 downto 0);
651	        variable DelayCycles_v : integer;
652	        variable WaitReady_v   : boolean;
653	        variable MsgPtr_v      : string_ptr_t;
654	    begin
655	
656	        -- loop messages
657	        loop
658	            -- wait until message available
659	            if is_empty(TxQueue_c) then
660	                wait until not is_empty(TxQueue_c) and rising_edge(Clk);
661	            end if;
662	            TxCheckOngoing <= true;
663	
664	            -- get message
665	            Msg_v     := pop(TxQueue_c);
666	            MsgType_v := message_type(Msg_v);
667	
668	            -- process message
669	            if MsgType_v = TxMsg_c then
670	                -- pop information
671	                Data_v        := pop(Msg_v);
672	                DelayCycles_v := pop(Msg_v);
673	                WaitReady_v   := pop(Msg_v);
674	                MsgPtr_v      := new_string_ptr(pop_string(Msg_v));
675	
676	                -- Apply Data
677	                if WaitReady_v then
678	                    wait_for_value_stdl(Tx_Ready, '1', 1 ms, "Tx_Ready not asserted: " & to_string(MsgPtr_v));
679	
680	                    for i in 1 to DelayCycles_v loop
681	                        wait until rising_edge(Clk);
682	                    end loop;
683	
684	                end if;
685	
686	                Tx_Valid <= '1';
687	                Tx_Data  <= Data_v;
688	                wait until rising_edge(Clk) and Tx_Ready = '1';
689	                wait until falling_edge(Clk);
690	                Tx_Data  <= (others => 'X');
691	                Tx_Valid <= '0';
692	                check_equal(Tx_Ready, '0', "Tx_Ready not de-asserted: " & to_string(MsgPtr_v));
693	            else
694	                error("Unexpected message type in vc_tx");
695	            end if;
696	            TxCheckOngoing <= false;
697	        end loop;
698	
699	    end process;
700	
701	end architecture;
702

